+import React, { useCallback, useRef } from 'react';
+import { Typography } from '@customink/pigment-react';
+import type { Breakpoint } from '../Molecules/ProductsCarousel/types';
+import { Carousel } from '../Atoms/Carousel';
+import type { CarouselHandle } from '../Atoms/Carousel';
+import { MiniProductCard } from '../Molecules/MiniProductCard';
+import { useBreakpoint } from '../hooks/useBreakpoint';
+import styles from './RecentlyViewedCarousel.module.css';
+
+import { ARROW_PATH } from '../Atoms/Carousel/constants';
+
+export type RecentlyViewedProduct = {
+  id: string | number;
+  name: string;
+  linkHref: string;
+  imageSrc: string;
+  imageSrcSet?: string;
+  imageAlt?: string;
+};
+
+export type RecentlyViewedCarouselProps = {
+  products: RecentlyViewedProduct[];
+  /** @default 'Pick Up Where You Left Off' */
+  title?: string;
+  /**
+   * `"large"` — h2 heading (homepage placement).
+   * `"compact"` — h4 heading (PDP placement).
+   * @default 'large'
+   */
+  variant?: 'large' | 'compact';
+  /**
+   * Show prev/next arrow buttons alongside the header on desktop and tablet.
+   * Hidden on mobile regardless of this setting.
+   * @default false
+   */
+  arrows?: boolean;
+  slidesConfig?: Partial<Record<Breakpoint, { perView: number; spacing: number }>>;
+  onCardClicked?: (product: RecentlyViewedProduct, index: number) => void;
+  children?: React.ReactNode;
+  className?: string;
+  style?: React.CSSProperties;
+};
+
+const DEFAULT_SLIDES_CONFIG: Record<Breakpoint, { perView: number; spacing: number }> = {
+  mobile: { perView: 2.3, spacing: 10 },
+  tablet: { perView: 3.4, spacing: 16 },
+  desktop: { perView: 6, spacing: 16 },
+};
+
+const TITLE_VARIANT = {
+  large: 'heading2',
+  compact: 'heading4',
+} as const;
+
+const ARROW_SIZE = {
+  large: 18,
+  compact: 14,
+} as const;
+
+type CardSlideProps = {
+  product: RecentlyViewedProduct;
+  index: number;
+  onCardClick: (product: RecentlyViewedProduct, index: number) => void;
+};
+
+function CardSlide({ product, index, onCardClick }: CardSlideProps) {
+  const handleClick = useCallback(() => onCardClick(product, index), [onCardClick, product, index]);
+
+  return (
+    <MiniProductCard
+      name={product.name}
+      linkHref={product.linkHref}
+      imageSrc={product.imageSrc}
+      imageSrcSet={product.imageSrcSet}
+      imageAlt={product.imageAlt}
+      onClick={handleClick}
+    />
+  );
+}
+
+export const RecentlyViewedCarousel = React.forwardRef<HTMLDivElement, RecentlyViewedCarouselProps>(
+  function RecentlyViewedCarousel(
+    {
+      products,
+      title = 'Pick Up Where You Left Off',
+      variant = 'large',
+      arrows = false,
+      slidesConfig,
+      onCardClicked,
+      children,
+      className,
+      style,
+    },
+    ref,
+  ) {
+    const breakpoint = useBreakpoint();
+    const { perView, spacing } = { ...DEFAULT_SLIDES_CONFIG[breakpoint], ...slidesConfig?.[breakpoint] };
+    const sliderRef = useRef<CarouselHandle>(null);
+    const canScroll = products.length > perView;
+    const showHeaderArrows = arrows && canScroll && breakpoint !== 'mobile';
+    const loop = showHeaderArrows;
+    const arrowSize = ARROW_SIZE[variant];
+
+    const handlePrev = useCallback(() => sliderRef.current?.prev(), []);
+    const handleNext = useCallback(() => sliderRef.current?.next(), []);
+    const handleCardClick = useCallback(
+      (product: RecentlyViewedProduct, index: number) => onCardClicked?.(product, index),
+      [onCardClicked],
+    );
+
+    if (products.length === 0) return null;
+
+    const rootClass = [styles.root, styles[variant], className].filter(Boolean).join(' ');
+
+    return (
+      <div ref={ref} className={rootClass} style={style} data-testid="recently-viewed-carousel">
+        <div className={styles.header}>
+          <Typography variant={TITLE_VARIANT[variant]} color="primary">
+            {title}
+          </Typography>
+          {showHeaderArrows ? (
+            <div className={styles.headerArrows} data-testid="header-arrows">
+              <button type="button" className={styles.headerArrow} onClick={handlePrev} aria-label="Previous">
+                <svg width={arrowSize} height={arrowSize} viewBox="0 0 24 24" fill="none" aria-hidden="true">
+                  <path
+                    fillRule="evenodd"
+                    clipRule="evenodd"
+                    d={ARROW_PATH}
+                    fill="currentColor"
+                    transform="scale(-1,1) translate(-24,0)"
+                  />
+                </svg>
+              </button>
+              <button type="button" className={styles.headerArrow} onClick={handleNext} aria-label="Next">
+                <svg width={arrowSize} height={arrowSize} viewBox="0 0 24 24" fill="none" aria-hidden="true">
+                  <path fillRule="evenodd" clipRule="evenodd" d={ARROW_PATH} fill="currentColor" />
+                </svg>
+              </button>
+            </div>
+          ) : null}
+        </div>
+
+        <Carousel slidesPerView={perView} spacing={spacing} loop={loop} arrows={false} sliderRef={sliderRef}>
+          {products.map((product, index) => (
+            <CardSlide key={product.id} product={product} index={index} onCardClick={handleCardClick} />
+          ))}
+        </Carousel>
+
+        {children}
+      </div>
+    );
+  },
+);
